const fs = require('fs');
const path = require('path');

const DATA_PATH = 'C:/projects/pjbroker/data/textbook-hi.json';
const data = JSON.parse(fs.readFileSync(DATA_PATH, 'utf8'));

// ─── Chapter 12: Health Insurance Underwriting ────────────────────────────────

const ch12 = data.chapters[11]; // index 11

// Section 0: Introduction
ch12.sections[0].paragraphs[0].textJP =
  'この章では、引受担当者が健康保険の申請を審査する際に何を確認するかについて説明します。';

// Section 1: What Is Underwriting?
ch12.sections[1].paragraphs[0].textJP =
  '引受（アンダーライティング）とは、保険者がリスクを評価し、申請を引き受けるかどうか、また引き受ける場合にはどのような条件で行うかを決定するプロセスです。引受により、徴収される保険料が各申請者のリスクと密接に対応するようになります。生命保険の引受が死亡率（一定の集団内での死亡発生率）を扱うのに対し、健康保険の引受は罹患率（一定期間内に集団の中で疾病や傷病が発生する割合）を扱います。';

// Section 2: Factors That Affect Risk
ch12.sections[2].paragraphs[0].textJP =
  'リスクに影響を与える要因は、（a）医学的要因と（b）非医学的要因に分類することができます。';

ch12.sections[2].paragraphs[1].textJP =
  '引受担当者は常に被保険者のリスク要因を評価しますが、第三者契約の保険料支払者のリスク要因も検討することがあります。';

// Section 3: Sources Of Underwriting Information
ch12.sections[3].paragraphs[0].textJP =
  '引受担当者は、判断を下すために様々な情報源から得た情報に依拠します。その情報源には、（a）申込書、（b）代理人の陳述書、（c）健康診断・検査、（d）主治医の陳述書（APS）、（e）補足質問票が含まれます。';

ch12.sections[3].paragraphs[1].textJP =
  '申込書以外に、引受担当者が被保険者に求める情報は、申込された保険の種類と規模によって異なります。高齢の被保険者や、給付額が高く保障期間が長い保険については、より多くの情報が必要となります。例えば、50歳の方が障害所得保険（月額S$10,000、65歳までの保障）を申し込む場合は、引受のためにより多くの情報が必要となります。';

// Section 4: How An Insurance Representative Can Help In The Underwriting
// P0 is just "PROCESS" (a heading fragment)
ch12.sections[4].paragraphs[0].textJP =
  'プロセス';

ch12.sections[4].paragraphs[1].textJP =
  '保険外交員は顧客と直接接触しているため、顧客を選別するうえで最も適切な立場にあります。実際、保険外交員はフィールド・アンダーライターとみなされています。';

ch12.sections[4].paragraphs[2].textJP =
  '保険外交員は、顧客が保険を購入する動機とニーズを明確にすることで貢献できます。申込書の質問事項を一つひとつ確認し、顧客が知る限りにおいて、すべての情報を誠実かつ正確に申告するよう案内する必要があります。';

ch12.sections[4].paragraphs[3].textJP =
  '申込書の回答に「はい」があった場合は、申込書の追加質問に基づき、顧客からできる限り詳細な情報を引き出す必要があります。';

ch12.sections[4].paragraphs[4].textJP =
  'こうした情報を収集することで、保険外交員は引受担当者が主治医の陳述書（APS）の請求や糖尿病に関する質問票への記入が必要かどうかを判断するのに役立てることができます。一方、顧客が「はい」と回答しながら詳細な情報を提供しなかった場合は、引受担当者がさらなる情報を求め、承認プロセスに遅れが生じることになります。';

ch12.sections[4].paragraphs[5].textJP =
  '申込書のすべての質問事項が、保険外交員の立会のもとで申込者によって適切に記入・署名されていることを確認することで、申込書を迅速に処理することができます。健康診断・検査や補足質問票が必要となるタイミングなど、引受ガイドラインを熟知していることも、引受プロセスの迅速化に役立ちます。';

// Section 5: Final Underwriting Decision
ch12.sections[5].paragraphs[0].textJP =
  '引受担当者は、以下に説明する承認条件のいずれかによって健康保険の申請を受け付ける場合があります。';

// Section 6: Commencement Of Risk
ch12.sections[6].paragraphs[0].textJP =
  '標準外リスクの場合、保険者は証券を発行する前に承認条件を申込者に通知します。申込者が承認書に記載された条件に同意し、保険料を支払った場合、保険が発効し、証券が発行されます。標準リスクの場合は、保険料の支払いをもって証券が発行されます。';

// Section 7: Conclusion
ch12.sections[7].paragraphs[0].textJP =
  '引受は、望ましくないリスクを排除し、徴収される保険料がリスクに対応していることを確保するための重要なプロセスです。引受担当者は、保険者を逆選択リスクから守るゲートキーパーとしての役割を担っています。保険外交員は引受プロセスと確認事項を理解し、顧客体験を円滑にする必要があります。\n\n付録12A：補足ライフスタイル質問票のサンプル\n被保険者氏名　生命保険申込番号　申込者氏名（被保険者と異なる場合）\n\nInsurance Act 1966（保険法）第23条第5項およびその後継規定に基づき、本補足質問票において、知っているまたは知るべきすべての事実を完全かつ誠実に開示してください。これを怠った場合、本書に基づいて発行される証券が無効となる可能性があります。\n\n後天性免疫不全症候群（AIDS）は生命保険における新しくも重大なリスクであり、現在のところ既知の治療法はありません。危険なスポーツ、職業、致死的疾患と同様に、生命保険会社はAIDSに罹患するリスクのある人物を特定することに関心を持っています。これは、新たな申込者全体に対する公平性を確保し、既存の保険契約者全員の積立金と配当を守るためです。これまでのところ、AIDSは特定のグループを主に（ただし排他的にではなく）侵してきました。そのため、生命保険業界は確立された生命選択の原則が維持されるよう、これらのリスクグループのメンバーを特定する必要があります（これは、高リスクグループのすべてのメンバーが保険加入を拒否されることを意味するものではありません）。また、この質問票は、多額の保険金額を申し込む方にも使用されます。この目的を達成するために、本書類に記入のうえ、同封の封筒でご返送ください。回答は厳重に機密として扱われます。記入にあたっては、各質問に完全かつ正確にお答えください。また、最下段の宣言事項をよくお読みください。これらの質問に関連する事実の不開示は、給付金の支払いに影響する場合があります。開示すべきかどうか迷う情報があれば、開示することを強くお勧めします。\n\n1. 以下のAID高リスクグループに属している、または過去に属していましたか？該当する場合はご記入ください。a.同性愛者 b.両性愛者 c.静脈内薬物使用者 d.血友病患者 e.売春従事者\n2. 質問(1)に記載されたAID高リスクグループのいずれかの人物と性的関係を持ったことがありますか？ある場合は、どのグループの人物と、いつ最後に接触したかをご記入ください。\n3. AIDSまたはAIDS関連状態に関連して検査を受けた、医療上の助言・カウンセリング・治療を受けた、またはAIDSやAIDS関連状態に罹患している可能性や、ヒト免疫不全ウイルス（HIV）を保有している可能性があるとして検査を受けたことがありますか？検査や助言を求めた経緯の詳細をご記入ください（献血目的の通常の検査は除きます）。\n4. 肝炎を含む性感染症に関連して検査を受けた、医療上の助言・治療を受けたことがありますか？ある場合は：a.過去に罹患した性感染症の種類を記入してください。 b.性感染症に感染した回数と日付を記入してください。 c.その際に診察を行った医師の氏名と住所を記入してください。\n5. 血液または臓器のドナーとして断られたことがありますか？ある場合は、いつ、誰に、どのような理由で断られたかをご記入ください。\n\n私（たち）は、上記の回答が私（たち）の知る限りにおいて真実かつ完全であり、この申請の評価または引受に影響を与え得るいかなる重要な情報も隠していないことを宣言します。また、私（たち）が回答した医師を含む、私の担当医から会社が情報を求めることに同意します。本書類が私（たち）の生命保険申込の一部を構成すること、および私（たち）が知っているすべての重要な事実を開示しない場合、契約が無効となる可能性があることに同意します。\n被保険者署名　申込者署名（被保険者と異なる場合）　日付\n\n付録12B：入院・外科手術保険個人申込書サンプル（ABC Life Limited）\n代理人コード：　証券番号：　代理人氏名：\n\n警告：Insurance Act 1966（保険法）第23条第5項に基づき、本申込書において、知っているまたは知るべきすべての事実を完全かつ誠実に開示してください。これを怠った場合、証券に基づき何も支払われない場合があります。';

// ─── Chapter 14: Financial Needs Analysis ────────────────────────────────────

const ch14 = data.chapters[13]; // index 13

// Section 0: Introduction
ch14.sections[0].paragraphs[0].textJP =
  'この章では、ニーズ分析のプロセス（事実確認、ニーズの特定と定量化、商品の推奨、推奨内容の提示、見直し）についてご説明します。LIA（生命保険協会）およびGIA（損害保険協会）の「A&H保険商品に関する開示要件とニーズに基づく販売プロセスに関するガイドライン」を常に把握しておくことが求められます。まず、ニーズ販売とプロダクト販売の違いを見ていきましょう。';

// Section 1: Needs Selling Versus Product Selling
ch14.sections[1].paragraphs[0].textJP =
  'ニーズ販売とプロダクト販売は以下の点で異なります。\n\n（a）サービス志向\n＜ニーズ販売＞見込み顧客のニーズを発見し、最も適切な商品と購入量についてアドバイスします。商品の説明よりも見込み顧客の状況に多くの時間を割きます。商品を売り込むのではなく、適切なニーズに基づくアドバイスプロセスを通じてサービスを提供します。\n＜プロダクト販売＞見込み顧客が自社商品を必要としていると仮定して、すぐに商品説明に入ります。しかし、そのような思い込みは、あなたの主な関心が商品を売って成約することだという印象を見込み顧客に与えかねません。\n\n（b）購買圧力\n＜ニーズ販売＞見込み顧客が自身のニーズに気づくよう支援し、適切な解決策を提案します。顧客の課題はあなたが来る前から存在しており、顧客が行動しなければ来訪後も残り続けます。商品の購入を強制するのではなく、ニーズに対する解決策を提示します。\n＜プロダクト販売＞購買圧力を生み出しますが、見込み顧客はなぜその商品が必要なのかを理解していない場合があります。たとえ商品が気に入っていても、人は圧力に抵抗するものです。\n\n（c）長期的な関係\n＜ニーズ販売＞商品ではなく見込み顧客の状況に焦点を当てます。あなたが商品を売ることよりも顧客の特定の状況を気にかけていること、ニーズを特定し関連する解決策を見つけるための知識と信頼があること、顧客の状況の理解に基づいて予算とニーズに合った解決策を提案すること、定期的にニーズを見直すことで継続的な関係を構築することを示します。\n＜プロダクト販売＞顧客との関係はその商品への満足度に依存します。購入決定前に様々な選択肢を検討したいのは顧客も同じです。顧客は商品意識が高くなり、常に最安値の解決策を期待するようになる可能性があります。最初の成約ができても、この顧客への次回の販売が最初より容易になるとは限りません。';

ch14.sections[1].paragraphs[1].textJP =
  '要約すると、ニーズ販売がプロダクト販売より望ましい理由は、（a）サービス志向であること、（b）圧力販売ではないこと、（c）関係性に基づいていること、の3点です。';

ch14.sections[1].paragraphs[2].textJP =
  'ニーズ販売を実践するためには、見込み顧客のことを知る必要があります（これはNotice No: MAS 120の要件です）。これは、Fact-Find Documentを用いた事実確認を行うことで達成できます。グループ向けの事実確認（Group Fact Find）もありますが、本章では詳細には触れません。';

// Section 2: What Is Fact-finding?
ch14.sections[2].paragraphs[0].textJP =
  '事実確認（ファクトファインディング）とは、見込み顧客の個人的な状況、財務状況、将来の目標などに関する一連の質問に回答を得るプロセスです。この情報により見込み顧客の目的、ニーズ、個人的なプロフィールをより深く理解することができ、見込み顧客に対して傷害・疾病（A&H）保険やその他の保険商品を適切に推奨するための適切な根拠を持つことができます。';

// Section 3: Identifying & Quantifying Needs (empty)
// (no paragraphs)

// Section 4: Product Recommendations
ch14.sections[4].paragraphs[0].textJP =
  '見込み顧客に商品を推奨する前に知っておくべき基本原則が3つあります。（a）見込み顧客が必要としている場合にのみ商品を推奨する、（b）見込み顧客の現在の状況を踏まえて最も適切な商品のみを推奨する、（c）見込み顧客が代理している会社が取り扱っていない商品を必要としている場合には、代替品を探せるよう見込み顧客に告知する、の3点です。';

// Section 5: Presenting Your Recommendations
ch14.sections[5].paragraphs[0].textJP =
  '見込み顧客が推奨された商品と推奨理由を理解できるよう、推奨商品の特徴・給付内容と、それが見込み顧客の状況にどのように合致するかを説明する必要があります。';

ch14.sections[5].paragraphs[1].textJP =
  '見込み顧客への推奨内容を説明するための面談前に、提示方法を計画しておくことをお勧めします。体系的なプロセスに従うことが望ましいです。';

ch14.sections[5].paragraphs[2].textJP =
  '以下に、見込み顧客への推奨内容を説明するための体系的かつ順序立てたプロセスの例を示します。\n1. 商品の目的（この商品によって実際にどのニーズが満たされるか）を説明する。\n2. 商品の性質について説明する。\n3. 商品の給付内容と制限事項を説明する。\n4. 商品内のオプションについて詳しく説明する。\n5. 商品を推奨する理由の概要を説明する。\n6. 給付内容のイラストを説明し、確定給付と不確定給付（該当する場合）を強調する。\n7. 証券に係る販売コスト、手数料および費用を開示する。';

ch14.sections[5].paragraphs[3].textJP =
  '面談中は、明確かつ平易に伝えてください。専門用語の使用は避けてください。見込み顧客が推奨内容を受け入れた場合は、保険者（保険会社）が必要とするすべての関連書類が適切に記入されていることを確認する必要があります。見込み顧客が推奨内容を受け入れない場合は、受け入れない理由を確認することができます。ただし、見込み顧客が説明を断った場合は、強要してはなりません。その場合は見込み顧客の時間に感謝して退席してください。';

// Section 6: Periodic Client Review
ch14.sections[6].paragraphs[0].textJP =
  '顧客のニーズを特定し満足させるプロセスは、最初の推奨内容の実施をもって終わるものではありません。顧客の個人的な状況は変化することが多く、時間の経過とともに新たなニーズが生じることもあります。このような変化は、当初の商品推奨が適切でなくなる可能性があるため影響を与えることがあります。定期的な見直しにより、既存顧客が継続して質の高いサービスを受けられるようにするとともに、顧客との関係をさらに強化することができます。';

ch14.sections[6].paragraphs[1].textJP =
  '既存顧客のポジションをいつ、どのくらいの頻度で見直すかは、当初に提供したアドバイスの内容や、既存顧客自身の見直し希望にある程度依存します。一般的には、以下のような状況で既存顧客との見直しを実施する必要があります。（a）子供の誕生など、顧客の個人的な状況の変化、（b）顧客の財務状況や保有する商品の適切性に影響を及ぼす可能性のあるCPF制度の変更など外部環境の変化、（c）顧客が当初購入した商品がすべてのニーズを満たすのに十分でなくなった場合、（d）金融サービス市場での新商品の発売。';

ch14.sections[6].paragraphs[2].textJP =
  '定期的な見直しは、あなたと顧客双方に利益をもたらします。プロの保険外交員として、推奨した商品が顧客の現在のニーズを満たしていることを確認する必要があります。また、将来のニーズに対応するため、定期的な面談の設定を心がけてください。';

ch14.sections[6].paragraphs[3].textJP =
  '顧客の長期的なニーズを最優先に考え、顧客との関係を継続的なものにしてください。顧客が十分な医療保障を持っている場合は、複数の保険証券では給付金を重複して請求できない可能性があるため、追加の健康保険証券を推奨しないでください。\n\n【第14章 重要概念まとめ】\n\nニーズ販売 vs プロダクト販売\nニーズ販売がプロダクト販売より望ましい理由：①サービス志向、②圧力販売ではない、③関係性に基づく。\n\n事実確認（ファクトファインディング）とは：見込み顧客の個人的状況・財務・将来の目標などに関する質問への回答を収集するプロセス。\n\nFact-Find Documentの各セクションの目的：\n▪ 顧客への重要なお知らせ：保険外交員の情報、代理する保険会社、提案できる商品クラスを顧客に伝える。正確な情報提供の重要性を強調する。\n▪ 申請タイプ：開示の種類、申請タイプ1・2・3。\n▪ 個人情報：会社の管理目的。必要な商品タイプの予備的評価。年齢情報は引受と保険料算定に必須。\n▪ 職業詳細：障害所得保険（DII）の適格性。DIIの待機期間の設定。職業上のリスクの有無。支払能力。\n▪ 配偶者・扶養家族の情報：請求時の識別、保険料算定、職業上のリスク（配偶者）、扶養家族としての適格性（A&H保険に年齢制限がある場合）、扶養家族の保障の必要性。\n▪ 既存健康保険/既存ポートフォリオ：既存プランが傷病・障害時のニーズをどの程度カバーするかを示す。\n▪ 個人の優先事項と目的：顧客が必要とするA&H保険の種類に関する優先順位を把握する。\n▪ 健康状態：被保険者が保険に加入できるか、またはどのような条件で加入できるかを判断する。\n▪ 外国人労働者向け医療保険：S-Pass/就労パス保有者のために購入する場合、Ministry of Manpowerの強化された医療保険要件への対応を確認する。\n▪ 証券の切替：顧客の回答が「はい」の場合、証券切替の影響を説明する。\n▪ 顧客の財務状況：推奨プランの支払能力の確認と財務ニーズ計画の策定を支援する。\n▪ アドバイザーの宣言：Fact-Find Documentの情報を厳重に機密として扱い、適切な保険商品の特定のみに使用すること（Personal Data Protection Act 2012の要件を念頭に置く）の宣言。代理人と顧客の信頼関係の確立。\n\nFact-Find Documentで顧客のニーズを特定する際の質問例：\n▪ 緊急資金はあるか？\n▪ 雇用状況と職業は？\n▪ ライフステージは？\n▪ 扶養家族はいるか？\n▪ 本人・扶養家族が個人生命・健康保険やグループ医療保険（グループCIや入院・外科手術保険等）に加入しているか？\n▪ 生命・健康保険の必要性があるか？\n▪ 提案する保険証券の保険料を支払えるか？\n▪ 優先事項は正しく述べられているか？\n\n緊急資金の重要性：家計の主な収入源の失業や短期的な障害による収入途絶に備える。\n\nライフステージと障害・疾病からの収入保護の必要性：\n▪ 就労期間中は、傷害や長期疾患による障害から収入を守ることが重要。\n▪ 傷病への備えはライフステージを問わずすべての人に必要。\n▪ 高齢者は傷病リスクが高いため、CI保険・医療費保険・長期ケア保険のニーズが高い。\n▪ 扶養家族がいる場合は、重大疾病や障害に備えた扶養家族の医療費のための手当てが必要。\n\n各保険タイプへの対応方法：\n▪ 障害所得保険（DII）：現在の収入との対比で保障額が十分かを確認。目標退職年齢までのカバレッジ・待機期間・雇用主からのDII給付があるかを確認。Limitation Clauseによる過剰保険に注意。\n▪ 高度障害（TPD）給付付き生命保険：既存の生命保険のTPD給付を確認。\n▪ 医療費保険（MEI）：入院病院・病室のタイプ・年間・生涯限度額・co-insurance・deductibleなどを確認。有効期限・更新条件を確認。Co-ordination of Benefit Clauseを念頭に置く。\n▪ CI保険：単独証券か他の証券のライダーかを確認。保険者の上限合計保険金額に注意。\n▪ 傷害保険：除外事項・制限を含む保障範囲を確認。\n▪ 長期ケア保険：給付内容・給付発動条件・ADLの定義・必要ADL数を確認。実費払戻タイプか確認。\n▪ 入院見舞金保険：1日あたりの給付金と給付日数の上限を確認。\n▪ 生命保険・従業員給付：会社の保険への加入状況・生命保険の有無を確認。\n\n障害所得保護ニーズの定量化：\n▪ 方法1：月収の75%が障害時の収入保護ニーズ。\n▪ 方法2：収入ではなく月次支出を使用して必要保障額を算出。\n▪ 方法3：高度障害（TPD）時に一時金給付を提供する方法。\n\n医療費・付帯費用の定量化：最も一般的な入院原因、治療費、希望する病院・病室タイプ、初日からの保障の必要性、退職後の保険料継続支払能力について顧客と協議する。\n\n入院見舞金ニーズの定量化：必要な保護水準 ＝ 月次総費用 − 既存の入院見舞金（月額）\n\nCI保険の定量化：計算は科学よりも技術的側面が強い。考慮すべき要素：最もかかりやすい重大疾病（家族の病歴が参考になる）、家族のニーズと費用、家族の依存度、MEIとDIIの充足度、希望する医療水準（私立か公立病院）、追加給付型か加速給付型のCI保険か（追加給付型は65歳で保障終了となることが多いが、加速給付型は通常終身生命保険に付加されるため終身保障）、早期診断給付・複数請求・糖尿病や精神疾患などの追加保障が必要か、顧客の好みと納得感。\n\n商品推奨前の基本原則：\n▪ 必要な場合にのみ商品を推奨する。\n▪ 顧客の状況に最も適した商品のみを推奨する。\n▪ 代理する会社が取り扱っていない商品が必要な場合、顧客に代替品を探せるよう告知する。\n\n商品理解のための質問例：\n▪ 商品ラインナップは？\n▪ 商品の目的（費用払戻か収入補償か）は？\n▪ 請求の適格要件は？\n▪ 待機期間はあるか？期間と発効日は？\n▪ 更新条件（保証更新・任意更新・条件付き更新・解約可能）は？\n▪ 除外事項・制限は？\n▪ CI保険の生存期間・DII保険の職業変更通知義務などの特別条項は？\n▪ Co-ordination of Benefit Clauseはあるか？\n▪ 免責（deductible）やco-insurance条項はあるか？\n▪ 1日・1年・生涯あたりの限度額は？\n▪ 給付金の支払時期・方法は？\n▪ 販売コスト・手数料・費用は？\n▪ 保障期間は？\n▪ 保険料・支払頻度・変更可能性は？\n▪ 保険料の支払猶予期間は？\n▪ 保険料不払いの場合の影響は？\n▪ 医的・非医的限度額（健康診断が必要となる引受ガイドライン）は？\n▪ 失効防止オプションがある証券タイプは？\n▪ 地理的な保障範囲の制限はあるか？\n\n商品選択における支払能力の重要性：\n▪ 支払能力は最も適した商品を選ぶ際の重要な要素。\n▪ ほとんどの証券は定期的な保険料支払いが必要で、最初の保険料が支払えても継続できるとは限らない。\n▪ 早期失効は顧客・保険外交員・保険者の誰にとっても利益にならない。\n\n証券選択のポイント：\n▪ 不足分のみをカバーする新証券を推奨して過剰保険を最小化する。\n▪ できる限り長い保障期間を確保する。\n▪ 長期的な保険料支払能力を確認する。\n▪ 過剰保険にならないようにする。\n▪ 正しい被保険者に保険をかける。\n▪ 扶養家族がいる場合は十分な死亡保障があるかを確認する。\n▪ ライダーで保険料節約になる場合は推奨する。\n▪ CI保険の追加給付型と加速給付型の2種類を確認する。\n▪ 有効期限・保険料の差・既存生命保険がある場合のCI特約（Waiver of Premium）について顧客と検討する。\n▪ 他の生命保険保護がある顧客にはCI Waiver of Premium特約を検討する。\n▪ 雇用主提供MEIに加入している顧客が追加MEIを必要とする場合は、雇用主提供プランを補完する商品を確認する。\n▪ 推奨商品の代替プランも確認する。\n\n見込み顧客への推奨内容説明プロセス例：\n▪ 商品の目的を述べる。▪ 商品の性質を説明する。▪ 給付内容と制限を説明する。▪ 商品内オプションを詳説する。▪ 推奨理由の概要を説明する。▪ 給付イラストを説明し、確定・不確定給付を強調する。▪ 販売コスト・手数料・費用を開示する。\n\n定期的な顧客見直しが必要なタイミング：\n▪ 子供の誕生などの個人的状況の変化。\n▪ CPF制度変更などの外部環境の変化。\n▪ 当初商品がすべてのニーズを満たすのに不十分になった場合。\n▪ 金融サービス市場での新商品の発売。';

