const ch15 = data.chapters[14]; // index 14

ch15.sections[0].paragraphs[0].textJP =
  'この章では、ニーズに基づく販売プロセス全体がどのように実施されるかを示す2つのケーススタディをご紹介します。';

ch15.sections[0].paragraphs[1].textJP =
  'ここで示す事例はすべての状況に対応する包括的なガイドとして使用することはできません。また、LIAおよびGIAの「A&H保険商品に関する開示要件とニーズに基づく販売プロセスに関するガイドライン」を常に把握しておく必要があります。\n\n2. ケーススタディ1 — 個人健康保険';

ch15.sections[0].paragraphs[2].textJP =
  'アンジェラは新規顧客のトミー・タン（シンガポール市民）と事実確認を実施しました。以下は彼女がFact-Find Documentから収集したデータの概要です。\nタン氏：35歳\nタン夫人：35歳、専業主婦\n息子：5歳\n娘：1歳';

ch15.sections[0].paragraphs[3].textJP =
  '既存の健康保険証券：\n▪ グループ入院・外科手術（H&S）保険（プランA）（付録15A参照）';

ch15.sections[0].paragraphs[4].textJP =
  'アンジェラはさらにトミーから以下の情報を得ました。（a）タン夫妻には死亡保障として十分なカバレッジがある。（b）家族の平均月次支出はS$3,000で、収入はS$6,000である。（c）入院などの緊急ニーズに備えた貯蓄のほかは、保障計画のための資金を別途確保していない。（d）自身にS$200,000、妻にS$100,000のCI保険を希望している。（e）末子が自立するまでの21年間、障害が生じた場合に妻の生活費が必要と考えている。（f）タン夫人が障害を負った場合に子供たちに必要な推定費用は月S$1,500である。（g）入院の場合は公立病院のAワードを希望する。（h）健康保険の予算は月S$700である。';

ch15.sections[0].paragraphs[5].textJP =
  '必要な情報を収集したのち、アンジェラはトミーとその家族のメンバーの保険ニーズの分析を進めます。';

